// Validate and extract webhook payload
const body = $input.first().json.body || $input.first().json;
const id = body.politician_id;
const name = body.politician_name;

if (!id || !name) {
  throw new Error('Required fields missing: politician_id, politician_name');
}
if (!/^[0-9a-f]{8}$/.test(id)) {
  throw new Error(`politician_id must be 8-char hex string, got: ${id}`);
}

return [{ json: {
  politician_id: id,
  politician_name: name,
  party: body.party || null,
  position: body.position || null,
  started_at: new Date().toISOString()
} }];

// Generate collection prompts for 3 channels across 10 categories
// V50: Gemini + Naver + Grok-X
const categories = ['expertise','leadership','vision','integrity','ethics','accountability','transparency','communication','responsiveness','publicinterest'];
const catKr = {
  expertise:'전문성', leadership:'리더십', vision:'비전', integrity:'청렴성',
  ethics:'윤리', accountability:'책임성', transparency:'투명성',
  communication:'소통', responsiveness:'대응력', publicinterest:'공익성'
};
const p = $('Validate Input').first().json;
const now = new Date();
const officialStart = new Date(now.getTime() - 4*365*24*60*60*1000);
const publicStart = new Date(now.getTime() - 2*365*24*60*60*1000);
const officialStr = officialStart.toISOString().split('T')[0];
const publicStr = publicStart.toISOString().split('T')[0];
const nowStr = now.toISOString().split('T')[0];

const batches = [];
for (const cat of categories) {
  // Gemini: OFFICIAL 36 + PUBLIC 24 = 60개 목표
  batches.push({
    channel: 'Gemini',
    category: cat,
    source_type: 'OFFICIAL',
    politician_id: p.politician_id,
    politician_name: p.politician_name,
    target_count: 36,
    prompt: `한국 정치인 "${p.politician_name}"의 ${catKr[cat]}(${cat}) 관련 공식 활동을 36개 찾아주세요.\n기간: ${officialStr} ~ ${nowStr} (최근 4년)\n출처: 국회 회의록, 정부 공식 문서, 법안, 예산안, 공식 발표, 의정 활동 등\n\n각 항목을 JSON 배열로 반환:\n[{"title":"제목","content":"요약 (200자 이내)","source_url":"URL","source_name":"출처명","published_date":"YYYY-MM-DD","sentiment":"negative|positive|free"}]`
  });
  batches.push({
    channel: 'Gemini',
    category: cat,
    source_type: 'PUBLIC',
    politician_id: p.politician_id,
    politician_name: p.politician_name,
    target_count: 24,
    prompt: `한국 정치인 "${p.politician_name}"의 ${catKr[cat]}(${cat}) 관련 언론 보도를 24개 찾아주세요.\n기간: ${publicStr} ~ ${nowStr} (최근 2년)\n출처: 뉴스 기사, 칼럼, 사설, 인터뷰, 방송 보도 등\n\n각 항목을 JSON 배열로 반환:\n[{"title":"제목","content":"요약 (200자 이내)","source_url":"URL","source_name":"출처명","published_date":"YYYY-MM-DD","sentiment":"negative|positive|free"}]`
  });
  // Naver: OFFICIAL 12개 + PUBLIC 48개 = 60개 (V40 비율: OFFICIAL 20%, PUBLIC 80%)
  batches.push({
    channel: 'Naver',
    category: cat,
    source_type: 'MIXED',
    politician_id: p.politician_id,
    politician_name: p.politician_name,
    official_count: 12,
    public_count: 48,
    target_count: 60,
    search_query: `${p.politician_name} ${catKr[cat]}`
  });
  // Grok-X: X(Twitter) 특화, 6개 (PUBLIC, sentiment=free 고정)
  batches.push({
    channel: 'GrokX',
    category: cat,
    source_type: 'PUBLIC',
    politician_id: p.politician_id,
    politician_name: p.politician_name,
    target_count: 6,
    prompt: `X(Twitter)에서 한국 정치인 "${p.politician_name}"의 ${catKr[cat]}(${cat}) 관련 최근 주목받은 트윗이나 반응을 6개 수집해주세요.\n기간: ${publicStr} ~ ${nowStr} (최근 2년)\n센티멘트 구분 없이 자유롭게 수집합니다.\n\nJSON 배열로 반환:\n[{"title":"트윗 요약","content":"내용 (200자 이내)","source_url":"트윗 URL 또는 X 링크","source_name":"X","published_date":"YYYY-MM-DD","sentiment":"free"}]`
  });
}
return batches.map(b => ({ json: b }));

// V50 Naver NCP API: OFFICIAL 12개 + PUBLIC 48개 = 60개
// NCP 유료 종량제 (X-NCP-APIGW-API-KEY)
const batch = $input.first().json;
const ncpKey = $env.NAVER_NCP_API_KEY;
const query = batch.search_query || batch.politician_name;
const officialCount = batch.official_count || 12;
const publicCount = batch.public_count || 48;

const ncpSearch = async (q, display) => {
  try {
    return await $helpers.httpRequest({
      method: 'GET',
      url: `https://naveropenapi.apigw.ntruss.com/web-search/v1/search?query=${encodeURIComponent(q)}&display=${display}&sort=date`,
      headers: {
        'X-NCP-APIGW-API-KEY': ncpKey,
        'Accept': 'application/json'
      }
    });
  } catch(e) { return { items: [] }; }
};

// OFFICIAL: site:go.kr 필터 (공공기관/국회/정부)
const officialResp = await ncpSearch(`${query} site:go.kr`, Math.min(officialCount * 2, 100));
const officialItems = ((officialResp.items || []).slice(0, officialCount))
  .map(item => ({ ...item, _source_type: 'OFFICIAL' }));

// PUBLIC: 일반 뉴스 (go.kr 제외)
const publicResp = await ncpSearch(query, Math.min(publicCount * 2, 100));
const publicItems = ((publicResp.items || [])
  .filter(item => !(item.link || '').includes('.go.kr'))
  .slice(0, publicCount))
  .map(item => ({ ...item, _source_type: 'PUBLIC' }));

return [{ json: { items: [...officialItems, ...publicItems] } }];

// Parse 3-channel collection responses into collected_data_v50 format
const items = $input.all();
const batchMeta = $('Collection Batch Loop').first().json;
const p = $('Validate Input').first().json;
const records = [];

for (const item of items) {
  const data = item.json;
  const meta = item.json._meta || batchMeta;

  // Parse Gemini response
  if (data.candidates && data.candidates[0]) {
    try {
      const text = data.candidates[0].content.parts[0].text || '';
      const match = text.match(/\[.*\]/s);
      if (match) {
        const parsed = JSON.parse(match[0]);
        for (const r of parsed) {
          records.push({
            politician_id: p.politician_id,
            category: meta.category || 'general',
            title: (r.title || '').substring(0, 500),
            content: (r.content || '').substring(0, 2000),
            source_url: r.source_url || '',
            source_name: r.source_name || 'Gemini',
            source_type: meta.source_type || 'OFFICIAL',
            published_date: r.published_date || null,
            sentiment: ['negative','positive','free'].includes(r.sentiment) ? r.sentiment : 'free',
            collector_ai: 'Gemini'
          });
        }
      }
    } catch (e) { /* skip parse errors */ }
  }

  // Parse Naver response (NCP API)
  if (data.items && Array.isArray(data.items)) {
    for (const r of data.items) {
      const title = (r.title || '').replace(/<[^>]*>/g, '');
      const desc = (r.description || r.content || '').replace(/<[^>]*>/g, '');
      const link = r.link || r.url || '';
      // source_type: _source_type 태그 우선, 없으면 도메인으로 자동 감지
      const isOfficial = r._source_type === 'OFFICIAL' || link.includes('.go.kr');
      records.push({
        politician_id: p.politician_id,
        category: meta.category || 'general',
        title: title.substring(0, 500),
        content: desc.substring(0, 2000),
        source_url: r.originallink || link,
        source_name: 'Naver',
        source_type: isOfficial ? 'OFFICIAL' : 'PUBLIC',
        published_date: r.pubDate ? new Date(r.pubDate).toISOString().split('T')[0] : null,
        sentiment: 'free',
        collector_ai: 'Naver'
      });
    }
  }

  // Parse Grok-X response (xAI Responses API format)
  if (data.output && Array.isArray(data.output)) {
    for (const outputItem of data.output) {
      const rawText = outputItem.content?.[0]?.text || (typeof outputItem.content === 'string' ? outputItem.content : '');
      if (!rawText) continue;
      try {
        const match = rawText.match(/\[.*\]/s);
        if (match) {
          const parsed = JSON.parse(match[0]);
          for (const r of parsed) {
            records.push({
              politician_id: p.politician_id,
              category: meta.category || 'general',
              title: (r.title || '').substring(0, 500),
              content: (r.content || '').substring(0, 2000),
              source_url: r.source_url || '',
              source_name: 'X',
              source_type: 'PUBLIC',
              published_date: r.published_date || null,
              sentiment: 'free',
              collector_ai: 'GrokX'
            });
          }
        }
      } catch (e) { /* skip parse errors */ }
    }
  }
}

return records.length > 0
  ? records.map(r => ({ json: r }))
  : [{ json: { _empty: true } }];

// After saving, feed back into Collection Batch Loop
// The loop will automatically terminate after all batches processed
return [{ json: $('Validate Input').first().json }];

const headers = $input.first().json.$response?.headers || {};
const range = headers['content-range'] || '0/0';
const total = parseInt(range.split('/')[1]) || 0;
const p = $('Validate Input').first().json;

const MIN_REQUIRED = 1000;
const gate = total >= MIN_REQUIRED ? 'pass' : 'fail';

return [{ json: {
  politician_id: p.politician_id,
  politician_name: p.politician_name,
  collected_total: total,
  gate: gate,
  message: gate === 'pass' ? `OK: ${total} records collected` : `WARN: only ${total} records (min ${MIN_REQUIRED})`
} }];

// Phase 2: Dedup + Period enforcement via Supabase REST
const p = $input.first().json;
const pid = p.politician_id;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

// Fetch ALL collected data with pagination (1000/page)
let allData = [];
let offset = 0;
while (true) {
  const chunk = await $helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/collected_data_v50?politician_id=eq.' + pid +
         '&limit=1000&offset=' + offset + '&order=id.asc',
    headers
  });
  const arr = Array.isArray(chunk) ? chunk : [];
  allData = allData.concat(arr);
  if (arr.length < 1000) break;
  offset += 1000;
}

const now = new Date();
const OFFICIAL_CUTOFF = new Date(now - 4 * 365.25 * 24 * 3600 * 1000);
const PUBLIC_CUTOFF   = new Date(now - 2 * 365.25 * 24 * 3600 * 1000);

const toDelete = new Set();

// 1) Period violations
for (const item of allData) {
  if (!item.published_date) continue;
  const d   = new Date(item.published_date);
  const src = (item.source_type || '').toUpperCase();
  if (src === 'OFFICIAL' && d < OFFICIAL_CUTOFF) toDelete.add(item.id);
  if (src === 'PUBLIC'   && d < PUBLIC_CUTOFF)   toDelete.add(item.id);
}

// 2) Dedup by normalised title (keep first occurrence)
const seen = new Map();
for (const item of allData) {
  if (toDelete.has(item.id)) continue;
  const norm = (item.title || '').toLowerCase().replace(/[\s\W]/g, '');
  if (!norm) continue;
  if (seen.has(norm)) {
    toDelete.add(item.id);
  } else {
    seen.set(norm, item.id);
  }
}

// 3) DELETE in chunks of 100
const ids = [...toDelete];
for (let i = 0; i < ids.length; i += 100) {
  const chunk = ids.slice(i, i + 100);
  await $helpers.httpRequest({
    method: 'DELETE',
    url: SUPABASE_URL + '/rest/v1/collected_data_v50?id=in.(' + chunk.join(',') +
         ')&politician_id=eq.' + pid,
    headers
  });
}

const remaining = allData.length - ids.length;
return [{ json: {
  politician_id:   pid,
  politician_name: p.politician_name,
  collected_total: allData.length,
  removed_count:   ids.length,
  remaining_total: remaining,
  validated:       true,
  phase:           'P2_complete'
} }];

// PATCH politicians.processing_status and pass through full input data
const p = $input.first().json;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

try {
  await $helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1/politicians?id=eq.' + p.politician_id,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({ processing_status: 'evaluating' })
  });
} catch (e) { /* non-fatal */ }

return [{ json: p }];

// Generate evaluation batches: 10 categories x 4 batch indices = up to 40 items
// batch_index 0..3 => offset 0,25,50,75 => up to 100 items/category
const categories = [
  'expertise','leadership','vision','integrity','ethics',
  'accountability','transparency','communication','responsiveness','publicinterest'
];
const p = $input.first().json;
const MAX_BATCHES = 4;

const batches = [];
for (const cat of categories) {
  for (let batchIndex = 0; batchIndex < MAX_BATCHES; batchIndex++) {
    batches.push({
      politician_id:   p.politician_id,
      politician_name: p.politician_name,
      category:        cat,
      batch_index:     batchIndex
    });
  }
}
return batches.map(b => ({ json: b }));

// Parse 4 AI evaluation responses into evaluations_v50 format
const items   = $input.all();
const batch   = $('Build Eval Prompt').first().json;
const records = [];

const validRatings = ['+4','+3','+2','+1','-1','-2','-3','-4','X'];

const aiParsers = [
  { name: 'Claude', extract: (d) => {
    if (d.content && d.content[0]) {
      const text  = d.content[0].text || '';
      const match = text.match(/\[[\s\S]*?\]/);
      return match ? JSON.parse(match[0]) : [];
    }
    return [];
  }},
  { name: 'Gemini', extract: (d) => {
    if (d.candidates && d.candidates[0]) {
      const text  = d.candidates[0].content?.parts?.[0]?.text || '';
      const match = text.match(/\[[\s\S]*?\]/);
      return match ? JSON.parse(match[0]) : [];
    }
    return [];
  }},
  { name: 'ChatGPT', extract: (d) => {
    if (d.choices && d.choices[0]) {
      const text  = d.choices[0].message?.content || '';
      const match = text.match(/\[[\s\S]*?\]/);
      return match ? JSON.parse(match[0]) : [];
    }
    return [];
  }},
  { name: 'Grok', extract: (d) => {
    if (d.output && d.output[0]) {
      const rawContent = d.output[0].content;
      const text = Array.isArray(rawContent)
        ? (rawContent[0]?.text || '')
        : (typeof rawContent === 'string' ? rawContent : '');
      const match = text.match(/\[[\s\S]*?\]/);
      return match ? JSON.parse(match[0]) : [];
    }
    return [];
  }}
];

const batchIds = new Set(batch.batch_item_ids || []);

for (let i = 0; i < Math.min(items.length, aiParsers.length); i++) {
  const parser = aiParsers[i];
  try {
    const evals = parser.extract(items[i].json);
    for (const ev of evals) {
      const rating = String(ev.rating || '').trim();
      if (!validRatings.includes(rating)) continue;
      // Only accept IDs that were actually in the fetched batch
      const cdId = ev.collected_data_id || null;
      if (cdId && !batchIds.has(cdId)) continue;
      records.push({
        politician_id:     batch.politician_id,
        category:          batch.category,
        evaluator_ai:      parser.name,
        collected_data_id: cdId,
        rating:            rating,
        reasoning:         (ev.reasoning || '').substring(0, 500)
      });
    }
  } catch (e) { /* skip malformed response */ }
}

return records.map(r => ({ json: r }));

// Phase 4: Calculate scores
// Formula: category_score = (6.0 + avg_score * 0.5) * 10
// avg_score = average of (rating * 2), X ratings excluded from denominator
// Final: round(min(sum(10 categories), 1000))

const PRIOR = 6.0;
const COEFFICIENT = 0.5;
const SCORE_MULTIPLIER = 2;
const GIVE_UP_THRESHOLD = 25;
const categories = ['expertise','leadership','vision','integrity','ethics','accountability','transparency','communication','responsiveness','publicinterest'];
const ratingMap = { '+4':4,'+3':3,'+2':2,'+1':1,'-1':-1,'-2':-2,'-3':-3,'-4':-4 };

const p = $('Validate Input').first().json;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;

// Fetch all evaluations with pagination (1000-row Supabase limit)
let allEvals = [];
let offset = 0;
while (true) {
  const batch = await $helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/evaluations_v50?politician_id=eq.' + p.politician_id +
         '&select=category,rating&offset=' + offset + '&limit=1000',
    headers: { apikey: supabaseKey, Authorization: 'Bearer ' + supabaseKey }
  });
  allEvals = allEvals.concat(batch);
  if (batch.length < 1000) break;
  offset += 1000;
}

const categoryScores = {};
let totalScore = 0;
const giveUpCategories = [];

for (const cat of categories) {
  const catEvals = allEvals.filter(e => e.category === cat && ratingMap[e.rating] !== undefined);

  if (catEvals.length < GIVE_UP_THRESHOLD) {
    // Give-up: leverage score 0 → category_score = PRIOR * 10 = 60
    categoryScores[cat] = Math.round(PRIOR * 10);
    giveUpCategories.push({ category: cat, count: catEvals.length });
  } else {
    const scores = catEvals.map(e => ratingMap[e.rating] * SCORE_MULTIPLIER);
    const avgScore = scores.reduce((a, b) => a + b, 0) / scores.length;
    const catScore = (PRIOR + avgScore * COEFFICIENT) * 10;
    categoryScores[cat] = Math.min(Math.max(Math.round(catScore), 20), 100);
  }
  totalScore += categoryScores[cat];
}

const finalScore = Math.round(Math.min(totalScore, 1000));

// Grade assignment
let grade;
if (finalScore >= 900) grade = 'S';
else if (finalScore >= 800) grade = 'A';
else if (finalScore >= 700) grade = 'B';
else if (finalScore >= 600) grade = 'C';
else if (finalScore >= 500) grade = 'D';
else grade = 'F';

return [{ json: {
  politician_id: p.politician_id,
  politician_name: p.politician_name,
  category_scores: categoryScores,
  final_score: finalScore,
  grade: grade,
  total_evaluations: allEvals.length,
  give_up_categories: giveUpCategories,
  calculated_at: new Date().toISOString()
} }];

// Phase 5: Generate HTML report content
const p = $('P4: Calculate Scores').first().json;
const now = new Date();
const dateStr = now.toISOString().split('T')[0].replace(/-/g, '');
const reportName = `${p.politician_name}_${dateStr}_${p.grade}`;

const catKr = {
  expertise:'전문성', leadership:'리더십', vision:'비전', integrity:'청렴성',
  ethics:'윤리', accountability:'책임성', transparency:'투명성',
  communication:'소통', responsiveness:'대응력', publicinterest:'공익성'
};

// Build category rows
const catRows = Object.entries(p.category_scores)
  .map(([cat, score]) => {
    const bar = Math.round(score);
    return `<tr><td>${catKr[cat] || cat}</td><td>${score}점</td><td><div style="width:${bar}%;background:#4CAF50;height:16px;border-radius:4px"></div></td></tr>`;
  })
  .join('\n');

const html = `<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${p.politician_name} AI 평가 보고서 (V50)</title>
<style>
  body { font-family: 'Noto Sans KR', sans-serif; margin: 0; padding: 20px; background: #f5f5f5; }
  .report { max-width: 900px; margin: 0 auto; background: white; border-radius: 12px; padding: 40px; box-shadow: 0 4px 20px rgba(0,0,0,0.1); }
  h1 { color: #1a237e; border-bottom: 3px solid #1a237e; padding-bottom: 12px; }
  .score-badge { display: inline-block; background: #1a237e; color: white; font-size: 2em; font-weight: bold; padding: 12px 28px; border-radius: 8px; margin: 16px 0; }
  .grade-badge { display: inline-block; background: #4CAF50; color: white; font-size: 1.5em; font-weight: bold; padding: 8px 20px; border-radius: 6px; margin-left: 16px; }
  table { width: 100%; border-collapse: collapse; margin-top: 20px; }
  th { background: #e8eaf6; padding: 10px; text-align: left; }
  td { padding: 10px; border-bottom: 1px solid #eee; }
  .footer { margin-top: 40px; font-size: 0.85em; color: #888; text-align: center; }
  .channel-note { background: #e3f2fd; border-left: 4px solid #1976d2; padding: 12px; border-radius: 4px; margin: 16px 0; font-size: 0.9em; }
  .pdf-btn { display: inline-block; margin: 16px 0; padding: 10px 24px; background: #1a237e; color: white; border: none; border-radius: 6px; font-size: 1em; cursor: pointer; text-decoration: none; }
  .pdf-btn:hover { background: #283593; }
  @media print {
    body { background: white; padding: 0; }
    .report { box-shadow: none; border-radius: 0; }
    .pdf-btn { display: none; }
  }
</style>
</head>
<body>
<div class="report">
  <h1>${p.politician_name} AI 평가 보고서</h1>
  <button class="pdf-btn" onclick="window.print()">📄 PDF 저장 (인쇄)</button>
  <div class="channel-note">V50 | 수집 채널: Gemini + Naver + Grok-X | 평가 AI: Claude · Gemini · ChatGPT · Grok</div>
  <div>
    <span class="score-badge">${p.final_score}점</span>
    <span class="grade-badge">${p.grade}등급</span>
  </div>
  <h2>카테고리별 점수</h2>
  <table>
    <thead><tr><th>카테고리</th><th>점수</th><th>분포</th></tr></thead>
    <tbody>
${catRows}
    </tbody>
  </table>
  <p style="margin-top:16px;color:#555">총 평가 건수: ${p.total_evaluations}건</p>
  <div class="footer">생성일: ${now.toLocaleDateString('ko-KR')} | PoliticianFinder.com V50 AI 평가 시스템</div>
</div>
</body>
</html>`;

return [{ json: {
  politician_id: p.politician_id,
  politician_name: p.politician_name,
  final_score: p.final_score,
  grade: p.grade,
  report_name: reportName,
  report_path: `v50/${reportName}.html`,
  html_content: html,
  generated_at: now.toISOString()
} }];

// PATCH politicians.processing_status and pass through full input data
const p = $input.first().json;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

try {
  await $helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1/politicians?id=eq.' + p.politician_id,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({ processing_status: 'validating' })
  });
} catch (e) { /* non-fatal */ }

return [{ json: p }];

// Phase 2-2: Count collected items per category (all sources combined)
const p = $input.first().json;
const pid = p.politician_id;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

// Fetch category column only (up to 5000 rows)
const resp = await $helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/collected_data_v50?politician_id=eq.' + pid +
       '&select=category&limit=1000',  // 1000/page; V50 target <1000 rows/politician
  headers
});
const rows = Array.isArray(resp) ? resp : [];

const catCounts = {};
for (const row of rows) {
  catCounts[row.category] = (catCounts[row.category] || 0) + 1;
}

const categories = [
  'expertise','leadership','vision','integrity','ethics',
  'accountability','transparency','communication','responsiveness','publicinterest'
];
const MIN = 50;
const shortCats = categories.filter(cat => (catCounts[cat] || 0) < MIN);
const round     = p.adjustment_round || 0;

// Force balance_ok if already hit max rounds (4)
const balance_ok = shortCats.length === 0 || round >= 4;

return [{ json: {
  ...p,
  balance_ok,
  adjustment_round: round,
  short_categories: shortCats,
  cat_counts:       catCounts,
  total_collected:  rows.length
} }];

// Phase 2-2: Recollect short categories via Gemini API
const p = $input.first().json;
const shortCats = p.short_categories || [];
const GEMINI_KEY    = $env.GEMINI_API_KEY;
const SUPABASE_URL  = $env.SUPABASE_URL;
const SUPABASE_KEY  = $env.SUPABASE_SERVICE_ROLE_KEY;

const supaHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};
const catKr = {
  expertise:'전문성', leadership:'리더십', vision:'비전', integrity:'청렴성',
  ethics:'윤리', accountability:'책임성', transparency:'투명성',
  communication:'소통', responsiveness:'대응력', publicinterest:'공익성'
};

let totalAdded = 0;
// Process up to 5 short categories per round
for (const cat of shortCats.slice(0, 5)) {
  const prompt =
    '정치인 "' + p.politician_name + '"의 ' + (catKr[cat] || cat) + ' 관련 최근 2년 이내 실제 뉴스/보도 30개를 수집하세요.\n' +
    '각 항목은 다음 JSON 배열 형식으로만 반환하세요:\n' +
    '[{"title":"제목","content":"내용 요약(200자)","source_name":"언론사","published_date":"YYYY-MM-DD","source_type":"PUBLIC"}]\n' +
    '반드시 실제 존재하는 뉴스만, 날짜 오늘 기준 최근 2년(PUBLIC) 또는 4년(OFFICIAL) 이내만 포함하세요.';

  let geminiResp;
  try {
    geminiResp = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-lite:generateContent?key=' + GEMINI_KEY,
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] })
    });
  } catch (e) { continue; }

  const text = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const match = text.match(/\[[\s\S]*\]/);
  if (!match) continue;

  let items;
  try { items = JSON.parse(match[0]); } catch (e) { continue; }

  const toSave = items.slice(0, 30).map(item => ({
    politician_id: p.politician_id,
    category:      cat,
    title:         (item.title   || '').substring(0, 500),
    content:       (item.content || '').substring(0, 2000),
    source_name:   item.source_name   || 'Gemini',
    source_url:    null,
    source_type:   item.source_type   || 'PUBLIC',
    published_date: item.published_date || null,
    sentiment:     'free',
    collector_ai:  'Gemini'
  }));

  if (toSave.length > 0) {
    await $helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/collected_data_v50',
      headers: supaHeaders,
      body: JSON.stringify(toSave)
    });
    totalAdded += toSave.length;
  }
}

return [{ json: {
  ...p,
  adjustment_round:     (p.adjustment_round || 0) + 1,
  last_recollect_added: totalAdded
} }];

// Fetch 25-item batch for current (category, batch_index) from Supabase
