// Embed fetched batch_items into the evaluation prompt
const p = $input.first().json;
const items = p.batch_items || [];

const catKr = {
  expertise:'전문성', leadership:'리더십', vision:'비전', integrity:'청렴성',
  ethics:'윤리', accountability:'책임성', transparency:'투명성',
  communication:'소통', responsiveness:'대응력', publicinterest:'공익성'
};

const basePrompt =
  '다음은 정치인 "' + p.politician_name + '"의 ' + (catKr[p.category] || p.category) + '(' + p.category + ') 관련 뉴스/활동 목록입니다.\n' +
  '각 항목에 대해 +4~-4 등급(0 제외, 절대 0 사용 금지)으로 평가하세요.\n' +
  'X는 해당 카테고리와 명백히 무관한 경우에만 사용하세요.\n\n' +
  '등급 기준:\n' +
  '+4: 매우 탁월한 성과 | +3: 우수한 성과 | +2: 양호한 성과 | +1: 소폭 긍정\n' +
  '-1: 소폭 부정 | -2: 문제 있음 | -3: 심각한 문제 | -4: 매우 심각한 문제\n\n' +
  'JSON 배열로만 반환 (다른 텍스트 없이):\n' +
  '[{"collected_data_id":"UUID","rating":"+3","reasoning":"평가 근거 (100자 이내)"}]\n\n' +
  '평가 대상 항목 (' + items.length + '개):\n';

const itemsList = items.map((item, i) => {
  const date    = item.published_date || '날짜미상';
  const title   = (item.title   || '').substring(0, 200);
  const content = (item.content || '').substring(0, 300);
  return (i + 1) + '. [ID:' + item.id + '] [' + date + '] ' + title + '\n   ' + content;
}).join('\n\n');

return [{ json: {
  ...p,
  full_prompt:    basePrompt + itemsList,
  batch_item_ids: items.map(x => x.id)
} }];
